import React, { useState, useEffect, useRef } from 'react';
import { Outlet, useNavigate, useLocation, NavLink } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import axios from 'axios';

const BusIcon = () => (
  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <rect x="1" y="3" width="22" height="14" rx="2"/><path d="M16 3v4M8 3v4M1 11h22M5 17v2M19 17v2"/>
  </svg>
);
const DashIcon = () => (
  <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/>
  </svg>
);
const StudentsIcon = () => (
  <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87M16 3.13a4 4 0 0 1 0 7.75"/>
  </svg>
);
const RouteIcon = () => (
  <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <circle cx="12" cy="12" r="10"/><line x1="2" y1="12" x2="22" y2="12"/><path d="M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/>
  </svg>
);
const FeesIcon = () => (
  <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/>
  </svg>
);
const CalIcon = () => (
  <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/>
  </svg>
);
const WarnIcon = () => (
  <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/>
  </svg>
);
const NotifIcon = () => (
  <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 0 1-3.46 0"/>
  </svg>
);
const ProfileIcon = () => (
  <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/>
  </svg>
);
const LogoutIcon = () => (
  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/>
  </svg>
);

const adminNav = [
  { section: 'Overview', items: [
    { to: '/admin/dashboard', label: 'Dashboard', icon: <DashIcon /> },
    { to: '/admin/reports', label: 'Reports & Analytics', icon: <CalIcon /> },
  ]},
  { section: 'Management', items: [
    { to: '/admin/students', label: 'Students', icon: <StudentsIcon /> },
    { to: '/admin/routes', label: 'Bus Routes', icon: <RouteIcon /> },
    { to: '/admin/fees', label: 'Fee Records', icon: <FeesIcon /> },
    { to: '/admin/passes', label: 'Bus Passes', icon: <FeesIcon /> },
    { to: '/admin/refunds', label: 'Refunds', icon: <WarnIcon /> },
  ]},
  { section: 'Scheduling', items: [
    { to: '/admin/schedules', label: 'Schedules', icon: <CalIcon /> },
    { to: '/admin/upcoming', label: 'Upcoming Dues', icon: <CalIcon /> },
    { to: '/admin/overdue', label: 'Overdue', icon: <WarnIcon /> },
    { to: '/admin/profile', label: 'Admin Profile', icon: <ProfileIcon /> },
  ]},
];

const studentNav = [
  { section: 'Portal', items: [
    { to: '/student/dashboard', label: 'Dashboard', icon: <DashIcon /> },
    { to: '/student/fees', label: 'Fees & Payments', icon: <FeesIcon /> },
    { to: '/student/schedule', label: 'Schedule', icon: <CalIcon /> },
    { to: '/student/passes', label: 'Bus Pass', icon: <ProfileIcon /> },
    { to: '/student/routes', label: 'Route Options', icon: <RouteIcon /> },
    { to: '/student/concessions', label: 'Concessions', icon: <CalIcon /> },
    { to: '/student/support', label: 'Support & Grievance', icon: <WarnIcon /> },
    { to: '/student/notifications', label: 'Notifications', icon: <NotifIcon /> },
    { to: '/student/profile', label: 'Profile', icon: <ProfileIcon /> },
  ]},
];

const pageTitles = {
  '/admin/dashboard': { title: 'Dashboard', sub: 'Overview and analytics' },
  '/admin/students': { title: 'Students', sub: 'Manage student records' },
  '/admin/routes': { title: 'Bus Routes', sub: 'Routes and fare structure' },
  '/admin/fees': { title: 'Fee Records', sub: 'Payment collection and tracking' },
  '/admin/schedules': { title: 'Schedules', sub: 'Due dates and late fee rules' },
  '/admin/upcoming': { title: 'Upcoming Dues', sub: 'Fees due within 30 days' },
  '/admin/overdue': { title: 'Overdue Fees', sub: 'Past-due payments requiring attention' },
  '/admin/profile': { title: 'Admin Profile', sub: 'Manage your administrator account' },
  '/student/dashboard': { title: 'Dashboard', sub: 'Account overview' },
  '/student/fees': { title: 'Fees & Payments', sub: 'Pay fees and view receipts' },
  '/student/schedule': { title: 'Schedule', sub: 'Due dates and payment policy' },
  '/student/profile': { title: 'My Profile', sub: 'Account and route information' },
  '/student/notifications': { title: 'Notifications', sub: 'Alerts and reminders' },
};

export default function Layout() {
  const { user, logout, isAdmin } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [notifications, setNotifications] = useState([]);
  const [showNotif, setShowNotif] = useState(false);
  const notifRef = useRef(null);

  useEffect(() => {
    axios.get('/notifications').then(r => setNotifications(r.data)).catch(() => {});
  }, [location.pathname]);

  useEffect(() => {
    const handler = (e) => {
      if (notifRef.current && !notifRef.current.contains(e.target)) setShowNotif(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const unread = notifications.filter(n => !n.isRead).length;
  const page = pageTitles[location.pathname] || { title: 'KEC Bus Portal', sub: '' };
  const navGroups = isAdmin ? adminNav : studentNav;

  const handleLogout = () => { logout(); navigate('/login'); };

  const markAllRead = async () => {
    await axios.put('/notifications/read-all');
    setNotifications(n => n.map(x => ({ ...x, isRead: true })));
  };

  const timeAgo = (date) => {
    const diff = Date.now() - new Date(date);
    const m = Math.floor(diff / 60000);
    if (m < 1) return 'just now';
    if (m < 60) return `${m}m ago`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}h ago`;
    return `${Math.floor(h / 24)}d ago`;
  };

  return (
    <div className="layout">
      {sidebarOpen && <div className="sidebar-overlay" onClick={() => setSidebarOpen(false)} />}
      <aside className={`sidebar ${sidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-logo">
          <div className="brand-mark">
            <BusIcon />
          </div>
          <div>
            <div className="brand-name">KEC Bus Fees</div>
            <div className="brand-sub">{isAdmin ? 'Administration' : 'Student Portal'}</div>
          </div>
        </div>
        <nav className="sidebar-nav">
          {navGroups.map(group => (
            <div key={group.section} className="nav-group">
              <div className="nav-section-label">{group.section}</div>
              {group.items.map(item => (
                <NavLink
                  key={item.to}
                  to={item.to}
                  className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
                  onClick={() => setSidebarOpen(false)}
                >
                  {item.icon}
                  <span>{item.label}</span>
                  {item.to === '/student/notifications' && unread > 0 && (
                    <span style={{
                      marginLeft: 'auto', background: '#dc2626', color: 'white',
                      fontSize: 10, fontWeight: 700, padding: '1px 6px', borderRadius: 10
                    }}>{unread}</span>
                  )}
                </NavLink>
              ))}
            </div>
          ))}
        </nav>
        <div className="sidebar-footer">
          <div className="user-card" onClick={() => navigate(isAdmin ? '/admin/profile' : '/student/profile')} style={{ cursor: 'pointer' }}>
            <div className="user-avatar">{user?.name?.charAt(0).toUpperCase()}</div>
            <div className="user-info">
              <div className="user-name">{user?.name}</div>
              <div className="user-role">{user?.role}</div>
            </div>
          </div>
          <button className="logout-btn" onClick={handleLogout}>
            <LogoutIcon /> Sign Out
          </button>
        </div>
      </aside>

      <main className="main-content">
        <header className="topbar">
          <div className="topbar-left">
            <button className="menu-toggle" onClick={() => setSidebarOpen(true)} aria-label="Open menu">☰</button>
            <div>
              <h2>{page.title}</h2>
              <p>{page.sub}</p>
            </div>
          </div>
          <div className="topbar-right">
            <span className="portal-name-topbar">KEC Bus Fees Portal</span>
            <span className="topbar-user">{user?.name}</span>
            <div style={{ position: 'relative' }} ref={notifRef}>
              <button className="notif-btn" onClick={() => setShowNotif(!showNotif)} title="Notifications" aria-label="Notifications">
                <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 0 1-3.46 0"/>
                </svg>
                {unread > 0 && <span className="notif-dot" />}
              </button>
              {showNotif && (
                <div className="notif-panel">
                  <div className="notif-header">
                    <span style={{ fontWeight: 700, fontSize: 14 }}>
                      Notifications {unread > 0 && <span className="badge badge-overdue" style={{ marginLeft: 6 }}>{unread}</span>}
                    </span>
                    {unread > 0 && <button className="btn btn-outline btn-sm" onClick={markAllRead}>Mark all read</button>}
                  </div>
                  <div className="notif-list">
                    {notifications.length === 0 ? (
                      <div className="notif-empty">🔔 No notifications</div>
                    ) : notifications.slice(0, 8).map(n => (
                      <div key={n.id} className={`notif-item ${!n.isRead ? 'unread' : ''}`}
                        onClick={() => {
                          axios.put(`/notifications/${n.id}/read`);
                          setNotifications(prev => prev.map(x => x.id === n.id ? { ...x, isRead: true } : x));
                        }}>
                        <div className="notif-item-title">{n.title}</div>
                        <div className="notif-item-msg">{n.message}</div>
                        <div className="notif-item-time">{timeAgo(n.createdAt)}</div>
                      </div>
                    ))}
                  </div>
                  <div className="notif-footer">
                    {!isAdmin && (
                      <button className="btn btn-outline btn-sm" onClick={() => { setShowNotif(false); navigate('/student/notifications'); }}>
                        View all
                      </button>
                    )}
                    <button className="btn btn-outline btn-sm" onClick={() => setShowNotif(false)}>Close</button>
                  </div>
                </div>
              )}
            </div>
            <div className="topbar-date">
              {new Date().toLocaleDateString('en-IN', { weekday: 'short', day: 'numeric', month: 'short', year: 'numeric' })}
            </div>
          </div>
        </header>
        <div className="page-content">
          <Outlet />
        </div>
      </main>
    </div>
  );
}
